<?php function fetch_goapi_quote($symbol, $apiKey) { $sym = str_replace(".JK", "", strtoupper($symbol)); $url = "https://api.goapi.io/stock/idx/prices?api_key=" . urlencode($apiKey) . "&symbols=" . urlencode($sym); $ch = curl_init(); curl_setopt($ch, CURLOPT_URL, $url); curl_setopt($ch, CURLOPT_RETURNTRANSFER, true); $res = curl_exec($ch); return $res; } echo fetch_goapi_quote("BBCA.JK", "f29dc087-640b-5b81-df7c-aee75f5e");
